    13→// process handles a bi-di stream request
    14→func (s *server) processADS(sw *streamWrapper, reqCh chan *discovery.DiscoveryRequest) error {
    15→	// Create a buffered multiplexed channel the size of the known resource types.
    16→	respChan := make(chan cache.Response, types.UnknownType)
    17→
    18→	// Instead of creating a separate channel for each incoming request and abandoning the old one
    19→	// This algorithm uses (and reuses) a single channel for all request types and guarantees
    20→	// the server will send updates over the wire in an ordered fashion.
    21→	// Downside is there is no longer back pressure per resource.
    22→	// There is potential for a dropped response from the cache but this is not impactful
    23→	// to the client since SOTW version handling is global and a new sequence will be
    24→	// initiated on a new request.
    25→	processAllExcept := func(typeURL string) error {
    26→		for {
    27→			select {
    28→			// We watch the multiplexed ADS channel for incoming responses.
    29→			case res := <-respChan:
    30→				if res.GetRequest().GetTypeUrl() != typeURL {
    31→					if err := sw.send(res); err != nil {
    32→						return err
    33→					}
    34→				}
    35→			default:
    36→				return nil
    37→			}
    38→		}
    39→	}
    40→
    41→	// This control loop strictly orders resources when running in ADS mode.
    42→	// It should be treated as a child process of the original process() loop
    43→	// and should return on close of stream or error. This will cause the
    44→	// cleanup routines in the parent process() loop to execute.
    45→	for {
    46→		select {
    47→		case <-s.ctx.Done():
    48→			return nil
    49→		// We only watch the multiplexed channel since we don't use per watch channels.
    50→		case res := <-respChan:
    51→			if err := sw.send(res); err != nil {
    52→				return status.Errorf(codes.Unavailable, err.Error())
    53→			}
    54→		case req, ok := <-reqCh:
    55→			// Input stream ended or failed.
    56→			if !ok {
    57→				return nil
    58→			}
    59→
    60→			// Received an empty request over the request channel. Can't respond.
    61→			if req == nil {
    62→				return status.Errorf(codes.Unavailable, "empty request")
    63→			}
    64→
    65→			// Only first request is guaranteed to hold node info so if it's missing, reassign.
    66→			if req.GetNode() != nil {
    67→				sw.node = req.GetNode()
    68→			} else {
    69→				req.Node = sw.node
    70→			}
    71→
    72→			// type URL is required for ADS but is implicit for xDS
    73→			typeURL := req.GetTypeUrl()
    74→			if typeURL == "" {
    75→				return status.Errorf(codes.InvalidArgument, "type URL is required for ADS")
    76→			}
    77→
    78→			if s.callbacks != nil {
    79→				if err := s.callbacks.OnStreamRequest(sw.ID, req); err != nil {
