    68→GrpcSubscriptionImpl::onConfigUpdate(const std::vector<Config::DecodedResourceRef>& resources,
    69→                                     const std::string& version_info) {
    70→  disableInitFetchTimeoutTimer();
    71→  // TODO(mattklein123): In the future if we start tracking per-resource versions, we need to
    72→  // supply those versions to onConfigUpdate() along with the xDS response ("system")
    73→  // version_info. This way, both types of versions can be tracked and exposed for debugging by
    74→  // the configuration update targets.
    75→  auto start = dispatcher_.timeSource().monotonicTime();
    76→  absl::Status status = callbacks_.onConfigUpdate(resources, version_info);
    77→  if (!status.ok()) {
    78→    return status;
    79→  }
    80→  std::chrono::milliseconds update_duration = std::chrono::duration_cast<std::chrono::milliseconds>(
    81→      dispatcher_.timeSource().monotonicTime() - start);
    82→  stats_.update_success_.inc();
    83→  stats_.update_attempt_.inc();
    84→  stats_.update_time_.set(DateUtil::nowToMilliseconds(dispatcher_.timeSource()));
    85→  stats_.version_.set(HashUtil::xxHash64(version_info));
    86→  stats_.version_text_.set(version_info);
    87→  stats_.update_duration_.recordValue(update_duration.count());
    88→  ENVOY_LOG(debug, "gRPC config for {} accepted with {} resources with version {}", type_url_,
    89→            resources.size(), version_info);
    90→
    91→  if (update_duration > UpdateDurationLogThreshold) {
    92→    ENVOY_LOG(debug, "gRPC config update took {} ms! Resources names: {}", update_duration.count(),
    93→              absl::StrJoin(resources, ",", ResourceNameFormatter()));
    94→  }
    95→  return absl::OkStatus();
    96→}
